operations.schema:
input SetTitleInput {
    title: String!
    updatedAt: DateTime!
}

operations.reducer:
if (action.input.description.length > 200) {
    throw new DescriptionTooLongError("Description exceeds 200 characters");
}
state.description = action.input.description;
if (state.provenance) {
    state.provenance.updatedAt = action.input.updatedAt;
}

operations.schema:
input SetDescriptionInput {
    description: String!
    updatedAt: DateTime!
}

input SetNoteTypeInput {
    noteType: String!
    updatedAt: DateTime!
}

input SetContentInput {
    content: String!
    updatedAt: DateTime!
}

operations.reducer:
const content = state.content || "";
const { offset, removeCount, insert } = action.input;
if (offset < 0 || offset + removeCount > content.length) {
    throw new PatchOutOfBoundsError("Offset + removeCount exceeds content length");
}
state.content = content.slice(0, offset) + insert + content.slice(offset + removeCount);
if (state.provenance) {
    state.provenance.updatedAt = action.input.updatedAt;
}

operations.schema:
input PatchContentInput {
    offset: Int!
    removeCount: Int!
    insert: String!
    updatedAt: DateTime!
}

operations.reducer:
const STRING_METADATA_FIELDS = [
    "scope", "confidence", "severity", "editor", "modelId", "version",
    "filePath", "computes", "context", "decisionStatus", "model",
    "sourceType", "targetType", "relationType", "cardinality",
    "errorMessage", "rootCause", "correctPattern"
];
const { field, value } = action.input;
if (!STRING_METADATA_FIELDS.includes(field)) {
    throw new InvalidMetadataFieldError(`"${field}" is not a recognized string metadata field`);
}
(state as any)[field] = value || null;
if (state.provenance) {
    state.provenance.updatedAt = action.input.updatedAt;
}

operations.schema:
input SetMetadataFieldInput {
    field: String!
    value: String
    updatedAt: DateTime!
}

operations.reducer:
const LIST_METADATA_FIELDS = [
    "models", "hooksUsed", "dispatchTargets", "modules", "inputs",
    "outputs", "consumedBy", "alternatives", "consequences"
];
const { field, values } = action.input;
if (!LIST_METADATA_FIELDS.includes(field)) {
    throw new InvalidMetadataListFieldError(`"${field}" is not a recognized list metadata field`);
}
(state as any)[field] = values;
if (state.provenance) {
    state.provenance.updatedAt = action.input.updatedAt;
}

operations.schema:
input SetMetadataListFieldInput {
    field: String!
    values: [String!]!
    updatedAt: DateTime!
}

operations.reducer:
state.provenance = {
    author: action.input.author,
    sourceOrigin: action.input.sourceOrigin,
    sessionId: action.input.sessionId || null,
    createdAt: action.input.createdAt,
    updatedAt: action.input.createdAt,
};

operations.schema:
input SetProvenanceInput {
    author: String!
    sourceOrigin: SourceOrigin!
    sessionId: String
    createdAt: DateTime!
}

operations.reducer:
const existing = state.links.find(l => l.id === action.input.id);
if (existing) {
    throw new DuplicateLinkIdError("A link with this OID already exists");
}
state.links.push({
    id: action.input.id,
    targetDocumentId: action.input.targetDocumentId,
    targetTitle: action.input.targetTitle || null,
    linkType: action.input.linkType,
});

operations.schema:
input AddLinkInput {
    id: OID!
    targetDocumentId: String!
    targetTitle: String
    linkType: LinkType!
}

operations.reducer:
const index = state.links.findIndex(l => l.id === action.input.id);
if (index === -1) {
    throw new LinkNotFoundError("No link with this OID");
}
state.links.splice(index, 1);

const link = state.links.find(l => l.id === action.input.id);
if (!link) {
    throw new LinkNotFoundError("No link with this OID");
}
link.linkType = action.input.linkType;

operations.schema:
input UpdateLinkTypeInput {
    id: OID!
    linkType: LinkType!
}

operations.reducer:
const duplicate = state.topics.find(t => t.name === action.input.name);
if (duplicate) {
    throw new DuplicateTopicError("A topic with this name already exists on this note");
}
state.topics.push({
    id: action.input.id,
    name: action.input.name,
    topicDocumentId: action.input.topicDocumentId || null,
});

operations.schema:
input AddTopicInput {
    id: OID!
    name: String!
    topicDocumentId: String
}

operations.reducer:
const index = state.topics.findIndex(t => t.id === action.input.id);
if (index === -1) {
    throw new TopicNotFoundError("No topic with this OID");
}
state.topics.splice(index, 1);

if (state.status !== "DRAFT") {
    throw new InvalidStatusTransitionError("Can only submit for review from DRAFT status");
}
state.status = "IN_REVIEW";
state.lifecycleEvents.push({
    id: action.input.id,
    fromStatus: "DRAFT",
    toStatus: "IN_REVIEW",
    actor: action.input.actor,
    timestamp: action.input.timestamp,
    comment: action.input.comment || null,
});
if (state.provenance) {
    state.provenance.updatedAt = action.input.timestamp;
}

operations.schema:
input SubmitForReviewInput {
    id: OID!
    actor: String!
    timestamp: DateTime!
    comment: String
}

operations.reducer:
if (state.status !== "IN_REVIEW") {
    throw new InvalidStatusTransitionError("Can only approve from IN_REVIEW status");
}
if (state.provenance && state.provenance.author === action.input.actor) {
    throw new SelfApprovalError("Actor cannot approve their own note");
}
state.status = "CANONICAL";
state.lifecycleEvents.push({
    id: action.input.id,
    fromStatus: "IN_REVIEW",
    toStatus: "CANONICAL",
    actor: action.input.actor,
    timestamp: action.input.timestamp,
    comment: action.input.comment || null,
});
if (state.provenance) {
    state.provenance.updatedAt = action.input.timestamp;
}

