operations.reducer:
if (state.status !== "ARCHIVED") {
    throw new InvalidStatusTransitionError("Can only restore from ARCHIVED status");
}
state.status = "DRAFT";
state.lifecycleEvents.push({
    id: action.input.id,
    fromStatus: "ARCHIVED",
    toStatus: "DRAFT",
    actor: action.input.actor,
    timestamp: action.input.timestamp,
    comment: action.input.comment || null,
});
if (state.provenance) {
    state.provenance.updatedAt = action.input.timestamp;
}

